+<!doctype html>
+<html lang="en">
+  <head>
+    <meta charset="utf-8" />
+    <meta name="viewport" content="width=device-width, initial-scale=1" />
+    <title>RepoBar</title>
+    <meta
+      name="description"
+      content="RepoBar is a macOS menu bar app for keeping an eye on your GitHub repos: CI state, issues, releases, traffic, and activity at a glance."
+    />
+    <link rel="preconnect" href="https://fonts.googleapis.com" />
+    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin />
+    <link
+      href="https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,600;9..144,700&family=IBM+Plex+Mono:wght@400;600&display=swap"
+      rel="stylesheet"
+    />
+    <style>
+      :root {
+        color-scheme: light;
+        --paper: #f4f0e8;
+        --ink: #141414;
+        --ink-muted: #3a3a3a;
+        --accent: #ff6b2d;
+        --accent-dark: #cf4c1a;
+        --line: #1f1f1f;
+        --panel: #ffffff;
+        --shadow: 0 24px 60px rgba(20, 20, 20, 0.2);
+        --radius: 18px;
+      }
+
+      * {
+        box-sizing: border-box;
+      }
+
+      body {
+        margin: 0;
+        font-family: "IBM Plex Mono", ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas,
+          "Liberation Mono", "Courier New", monospace;
+        color: var(--ink);
+        background: radial-gradient(1200px 600px at 20% -10%, #ffe4d6 0%, transparent 60%),
+          radial-gradient(900px 520px at 90% 10%, #ffe9c2 0%, transparent 65%),
+          linear-gradient(180deg, #f7f3ec 0%, #efe8dd 100%);
+        min-height: 100vh;
+        position: relative;
+      }
+
+      body::before {
+        content: "";
+        position: fixed;
+        inset: 0;
+        pointer-events: none;
+        background-image: repeating-linear-gradient(
+            90deg,
+            rgba(0, 0, 0, 0.035) 0,
+            rgba(0, 0, 0, 0.035) 1px,
+            transparent 1px,
+            transparent 9px
+          ),
+          repeating-linear-gradient(
+            0deg,
+            rgba(0, 0, 0, 0.03) 0,
+            rgba(0, 0, 0, 0.03) 1px,
+            transparent 1px,
+            transparent 12px
+          );
+        mix-blend-mode: multiply;
+        opacity: 0.35;
+      }
+
+      .frame {
+        max-width: 1100px;
+        margin: 0 auto;
+        padding: 80px 28px 96px;
+      }
+
+      header {
+        display: flex;
+        align-items: center;
+        justify-content: space-between;
+        gap: 20px;
+        border: 1px solid var(--line);
+        padding: 14px 18px;
+        background: var(--panel);
+        border-radius: 999px;
+        box-shadow: var(--shadow);
+      }
+
+      .logo {
+        display: flex;
+        align-items: center;
+        gap: 12px;
+        font-family: "Fraunces", "Times New Roman", serif;
+        font-size: 22px;
+        font-weight: 700;
+        letter-spacing: 0.02em;
+      }
+
+      .logo-badge {
+        width: 38px;
+        height: 38px;
+        border-radius: 14px;
+        background: conic-gradient(from 220deg, var(--accent), #ffb01f, #ffc86d, var(--accent));
+        border: 1px solid var(--line);
+        display: grid;
+        place-items: center;
+        color: var(--ink);
+        font-weight: 700;
+        font-size: 16px;
+      }
+
+      .nav-meta {
+        font-size: 12px;
+        text-transform: uppercase;
+        letter-spacing: 0.16em;
+        color: var(--ink-muted);
+      }
+
+      .hero {
+        margin-top: 52px;
+        display: grid;
+        grid-template-columns: minmax(280px, 1fr) minmax(280px, 1fr);
+        gap: 40px;
+        align-items: center;
+      }
+
+      .hero h1 {
+        font-family: "Fraunces", "Times New Roman", serif;
+        font-size: clamp(36px, 5vw, 62px);
+        line-height: 1.02;
+        margin: 0 0 18px;
+      }
+
+      .hero p {
+        font-size: 15px;
+        line-height: 1.7;
+        color: var(--ink-muted);
+        margin: 0 0 22px;
+        max-width: 44ch;
+      }
+
+      .feature-list {
+        margin: 0 0 26px;
+        padding: 0;
+        list-style: none;
+        display: grid;
+        gap: 8px;
+      }
+
+      .feature-list li {
+        display: flex;
+        gap: 10px;
+        align-items: baseline;
+        font-size: 14px;
+      }
+
+      .feature-list span {
+        color: var(--accent-dark);
+        font-weight: 600;
+      }
+
+      .cta-row {
+        display: flex;
+        flex-wrap: wrap;
+        gap: 12px;
+        align-items: center;
+      }
+
+      .button {
+        display: inline-flex;
+        align-items: center;
+        gap: 10px;
+        padding: 12px 18px;
+        border-radius: 999px;
+        border: 1px solid var(--line);
+        background: var(--ink);
+        color: #fff8f0;
+        font-size: 13px;
+        text-decoration: none;
+        letter-spacing: 0.08em;
+        text-transform: uppercase;
+        box-shadow: 0 12px 30px rgba(20, 20, 20, 0.2);
+        transition: transform 0.2s ease, box-shadow 0.2s ease;
+      }
+
+      .button:hover {
+        transform: translateY(-2px);
+        box-shadow: 0 18px 36px rgba(20, 20, 20, 0.25);
+      }
+
+      .button.secondary {
+        background: var(--panel);
+        color: var(--ink);
+      }
+
+      .button svg {
+        width: 16px;
+        height: 16px;
+      }
+
+      .panel {
+        background: var(--panel);
+        border: 1px solid var(--line);
+        border-radius: var(--radius);
+        padding: 18px;
+        box-shadow: var(--shadow);
+      }
+
+      .screenshot {
+        display: grid;
+        gap: 12px;
+      }
+
+      .screenshot img {
+        width: 100%;
+        display: block;
+        border-radius: 14px;
+        border: 1px solid var(--line);
+        background: #f8f8f8;
+      }
+
+      .screenshot-note {
+        font-size: 12px;
+        color: var(--ink-muted);
+        text-transform: uppercase;
+        letter-spacing: 0.14em;
+      }
+
+      footer {
+        margin-top: 64px;
+        display: flex;
+        justify-content: space-between;
+        font-size: 12px;
+        text-transform: uppercase;
+        letter-spacing: 0.16em;
+        color: var(--ink-muted);
+      }
+
+      @media (max-width: 880px) {
+        header {
+          flex-direction: column;
+          align-items: flex-start;
+        }
+
+        .hero {
+          grid-template-columns: 1fr;
+        }
+
+        footer {
+          flex-direction: column;
+          gap: 8px;
+        }
+      }
+    </style>
+  </head>
+  <body>
+    <div class="frame">
+      <header>
+        <div class="logo">
+          <div class="logo-badge">RB</div>
+          RepoBar
+        </div>
+        <div class="nav-meta">macOS menu bar intelligence for GitHub</div>
+      </header>
+
+      <main class="hero">
+        <section>
+          <h1>Stay ahead of your repositories without opening a browser.</h1>
+          <p>
+            RepoBar is a focused macOS menu bar app that surfaces the signal you care about:
+            CI status, issues and PR counts, releases, traffic, and a compact activity heatmap
+            for every repo you pin.
+          </p>
+          <ul class="feature-list">
+            <li><span>01</span> Real-time CI state with fast jump to Actions or Checks.</li>
+            <li><span>02</span> Releases, activity, and traffic in a single glanceable grid.</li>
+            <li><span>03</span> Built for power users: pin, sort, and refresh on your schedule.</li>
+          </ul>
+          <div class="cta-row">
+            <a
+              class="button"
+              href="https://github.com/steipete/RepoBar/releases/latest"
+              rel="noreferrer"
+            >
+              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
+                <path d="M12 3v12" />
+                <path d="M7 10l5 5 5-5" />
+                <path d="M4 21h16" />
+              </svg>
+              Download latest
+            </a>
+            <a
+              class="button secondary"
+              href="https://github.com/steipete/RepoBar"
+              rel="noreferrer"
+            >
+              <svg viewBox="0 0 24 24" fill="currentColor">
+                <path
+                  d="M12 2C6.48 2 2 6.58 2 12.24c0 4.5 2.87 8.32 6.84 9.67.5.1.68-.22.68-.48 0-.24-.01-.88-.01-1.72-2.78.62-3.37-1.36-3.37-1.36-.46-1.17-1.12-1.48-1.12-1.48-.92-.64.07-.63.07-.63 1.02.07 1.55 1.07 1.55 1.07.9 1.58 2.36 1.12 2.94.85.09-.67.35-1.12.63-1.38-2.22-.26-4.56-1.14-4.56-5.06 0-1.12.39-2.03 1.03-2.75-.1-.26-.45-1.32.1-2.75 0 0 .84-.27 2.75 1.05a9.3 9.3 0 012.5-.35c.85 0 1.7.12 2.5.35 1.9-1.32 2.75-1.05 2.75-1.05.55 1.43.2 2.49.1 2.75.64.72 1.03 1.63 1.03 2.75 0 3.93-2.35 4.79-4.59 5.05.36.32.69.93.69 1.88 0 1.36-.01 2.46-.01 2.79 0 .26.18.59.69.49 3.96-1.35 6.83-5.17 6.83-9.67C22 6.58 17.52 2 12 2z"
+                />
+              </svg>
+              GitHub
+            </a>
+          </div>
+        </section>
+
+        <aside class="panel screenshot">
+          <img src="assets/screenshot-placeholder.svg" alt="RepoBar app screenshot" />
+          <div class="screenshot-note">Screenshot placeholder. Replace with real UI soon.</div>
+        </aside>
+      </main>
+
+      <footer>
+        <div>RepoBar for macOS</div>
+        <div>Built by @steipete</div>
+      </footer>
+    </div>
+  </body>
+</html>
